 1	/* eslint-disable tsdoc/syntax */
 2	import * as _ from 'lodash-es';
 3	import * as React from 'react';
 4	import classNames from 'classnames';
 5	import * as PropTypes from 'prop-types';
 6	import { Alert, AlertGroup } from '@patternfly/react-core';
 7	import { useTranslation } from 'react-i18next';
 8	import { LoadingInline } from '../status/status-box';
 9	
10	const injectDisabled = (children, disabled) => {
11	  return React.Children.map(children, (c) => {
12	    if (!_.isObject(c) || c.type !== 'button') {
13	      return c;
14	    }
15	
16	    return React.cloneElement(c, { disabled: c.props.disabled || disabled });
17	  });
18	};
19	
20	const ErrorMessage = ({ message }) => {
21	  const { t } = useTranslation('plugin__pipelines-console-plugin');
22	  return (
23	    <Alert
24	      isInline
25	      className="co-alert co-alert--scrollable"
26	      variant="danger"
27	      title={t('An error occurred')}
28	      data-test="alert-error"
29	    >
30	      <div className="co-pre-line">{message}</div>
31	    </Alert>
32	  );
33	};
34	const InfoMessage = ({ message }) => (
35	  <Alert
36	    isInline
37	    className="co-alert"
38	    variant="info"
39	    title={message}
40	    data-test="button-bar-info-message"
41	  />
42	);
43	const SuccessMessage = ({ message }) => (
44	  <Alert isInline className="co-alert" variant="success" title={message} />
45	);
46	
47	// NOTE: DO NOT use <a> elements within a ButtonBar.
48	// They don't support the disabled attribute, and therefore
49	// can't be disabled during a pending promise/request.
50	/** @type {React.SFC<{children: any, className?: string, errorMessage?: React.ReactNode, infoMessage?: string, successMessage?: string, inProgress?: boolean}}>} */
51	export const ButtonBar = ({
52	  children,
53	  className,
54	  errorMessage,
55	  infoMessage,
56	  successMessage,
57	  inProgress,
58	}) => {
59	  return (
60	    <div className={classNames(className, 'co-m-btn-bar')}>
61	      <AlertGroup
62	        isLiveRegion
63	        aria-live="polite"
64	        aria-atomic="false"
65	        aria-relevant="additions text"
66	      >
67	        {successMessage && <SuccessMessage message={successMessage} />}
68	        {errorMessage && <ErrorMessage message={errorMessage} />}
69	        {injectDisabled(children, inProgress)}
70	        {inProgress && <LoadingInline />}
71	        {infoMessage && <InfoMessage message={infoMessage} />}
72	      </AlertGroup>
73	    </div>
74	  );
75	};
76	
77	ButtonBar.propTypes = {
78	  children: PropTypes.node.isRequired,
79	  successMessage: PropTypes.string,
80	  errorMessage: PropTypes.node,
81	  infoMessage: PropTypes.string,
82	  inProgress: PropTypes.bool,
83	  className: PropTypes.string,
84	};

